import json, re

funding_data = var_functions.query_db_4
civic_docs = var_functions.query_db_6

# Build funding map
def clean_name(name):
    return re.sub(r'\s*\([^)]*\)\s*$', '', name).strip()

funding_map = {}
for rec in funding_data:
    cname = clean_name(rec['Project_Name'])
    funding_map[cname] = {
        'source': rec['Funding_Source'],
        'amount': int(rec['Amount']),
        'full_name': rec['Project_Name']
    }

# Process documents
results = []

for doc in civic_docs:
    text = doc['text']
    lines = text.split('\n')

    for idx, line in enumerate(lines):
        line = line.strip()

        # Check if line looks like a project name
        if len(line) > 15 and (line.istitle() or line.isupper()):
            if all(x not in line for x in ['PROJECT', 'COMMISSION', 'MEETING', 'AGENDA', 'PUBLIC WORKS']):
                low = line.lower()
                if any(k in low for k in ['project', 'repair', 'improvement', 'drainage', 'sirens', 'warning', 'canyon', 'road']):
                    cname = clean_name(line)

                    # Find status in nearby lines
                    status = None
                    start = max(0, idx-3)
                    end = min(len(lines), idx+8)

                    for j in range(start, end):
                        cl = lines[j].lower()
                        if 'design' in cl or 'finalizing' in cl or 'plans' in cl:
                            status = 'design'
                            break
                        elif 'construction' in cl or 'under construction' in cl or 'bid' in cl:
                            status = 'construction'
                            break
                        elif 'completed' in cl or 'completion' in cl or 'finished' in cl:
                            status = 'completed'
                            break
                        elif 'not started' in cl or 'waiting' in cl or 'future' in cl:
                            status = 'not started'
                            break

                    if cname in funding_map:
                        results.append({
                            'Project_Name': line,
                            'Funding_Source': funding_map[cname]['source'],
                            'Amount': funding_map[cname]['amount'],
                            'Status': status
                        })

# Remove duplicates
unique = {}
for r in results:
    key = r['Project_Name']
    if key not in unique:
        unique[key] = r

output = list(unique.values())

print('__RESULT__:')
print(json.dumps(output, indent=2))

